"use client";

import * as React from "react";
import {
  IconArrowLeft,
  IconBox,
  IconMapPin,
  IconPhone,
  IconTruckDelivery,
  IconUser,
} from "@tabler/icons-react";
import {
  Alert,
  AlertDescription,
  AlertTitle,
  Badge,
  BottomActionBar,
  Button,
  Card,
  CardContent,
  DatePicker,
  ListCard,
  PageHeader,
  RadioCard,
  RadioCardGroup,
  RouteStops,
  type RouteStopItem,
  SegmentedControl,
  Separator,
  Statistic,
  Switch,
} from "@gunjo/ui";
import { ja } from "date-fns/locale";

import {
  CARRIER,
  DRIVER,
  NOTIFY_CHANNELS,
  PAST_PARCELS,
  RECEIVE_METHODS,
  RECIPIENT,
  SENDER,
  TIME_BANDS,
  TRACKING_NO,
  TRACKING_STEPS,
  type TrackingStep,
  dayHeadingFor,
  formatJaLongDate,
} from "./data";

/** ドメインの step.state → RouteStops の status へ。 */
function toRouteStatus(s: TrackingStep["state"]): RouteStopItem["status"] {
  switch (s) {
    case "completed":
      return "completed";
    case "current":
      return "current";
    case "failed":
      return "failed";
    default:
      return "pending";
  }
}

const PAST_TONE: Record<
  (typeof PAST_PARCELS)[number]["tone"],
  React.ComponentProps<typeof Badge>["variant"]
> = {
  delivered: "success",
  absent: "warning",
  active: "info",
};

export default function ParcelTrackingPage() {
  // 再配達フォームの状態
  const [redeliveryDate, setRedeliveryDate] = React.useState<Date | undefined>(
    new Date("2026-06-30T00:00:00"),
  );
  const [timeBand, setTimeBand] = React.useState<string>("1820");
  const [receiveMethod, setReceiveMethod] = React.useState<string>("home");

  // 通知設定の状態
  const [notify, setNotify] = React.useState<Record<string, boolean>>({
    push: true,
    line: true,
    mail: false,
  });

  const isAbsent = TRACKING_STEPS.some((s) => s.state === "failed");

  const bandLabel = TIME_BANDS.find((b) => b.value === timeBand)?.label ?? "";
  const methodLabel =
    RECEIVE_METHODS.find((m) => m.value === receiveMethod)?.label ?? "";
  const dateLabel = redeliveryDate ? formatJaLongDate(redeliveryDate) : "未選択";

  // RouteStops は時刻 (HH:MM) しか持てないため、日付はタイトル横の meta と
  // description に流し込む。さらに「日替わり」の見出しを各日の先頭に差し込む。
  const stops: RouteStopItem[] = TRACKING_STEPS.map((step, i) => {
    const heading = dayHeadingFor(TRACKING_STEPS, i);
    return {
      id: step.id,
      title: step.label,
      // 日替わりの見出しを meta に出す（RouteStops にはdate軸が無いための補完）
      meta: heading ? `${heading}` : undefined,
      description: (
        <span className="flex flex-col gap-0.5">
          {step.branch ? (
            <span className="inline-flex items-center gap-1">
              <IconMapPin className="size-3.5 shrink-0" aria-hidden="true" />
              {step.branch}
            </span>
          ) : null}
          {step.note ? <span>{step.note}</span> : null}
        </span>
      ),
      status: toRouteStatus(step.state),
      // RouteStops の time は HH:MM のみ。日付は meta 側で補う。
      actualTime: step.time,
    };
  });

  return (
    <div className="mx-auto flex min-h-dvh w-full max-w-md flex-col bg-background pb-32">
      <PageHeader
        sticky
        title="お荷物の追跡"
        subtitle={CARRIER.service}
        leading={
          <button
            type="button"
            aria-label="戻る"
            className="-ml-2 inline-flex size-11 shrink-0 items-center justify-center rounded-md text-foreground hover:bg-accent focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring"
          >
            <IconArrowLeft className="size-5" aria-hidden="true" />
          </button>
        }
        actions={
          <a
            href={`tel:${CARRIER.supportTel}`}
            aria-label="サポートに電話する"
            className="inline-flex size-11 items-center justify-center rounded-md text-foreground hover:bg-accent focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring"
          >
            <IconPhone className="size-5" aria-hidden="true" />
          </a>
        }
      />

      <main className="flex flex-col gap-5 px-4 pt-4">
        {/* ── 追跡中の荷物のサマリ（ヒーロー） ── */}
        <section aria-labelledby="summary-heading">
          <h2 id="summary-heading" className="sr-only">
            お荷物のサマリ
          </h2>
          <Card>
            <CardContent className="flex flex-col gap-4 p-4">
              <div className="flex items-start justify-between gap-3">
                <div className="flex min-w-0 flex-col gap-1">
                  <span className="text-xs text-muted-foreground">
                    お問い合わせ番号
                  </span>
                  <span className="font-mono text-base font-semibold tabular-nums tracking-wide text-foreground">
                    {TRACKING_NO}
                  </span>
                </div>
                <Badge variant={isAbsent ? "warning" : "info"}>
                  {isAbsent ? "ご不在" : "配達中"}
                </Badge>
              </div>

              <Separator />

              <div className="flex items-center gap-3">
                <span className="inline-flex size-11 shrink-0 items-center justify-center rounded-full bg-info-subtle text-info">
                  <IconTruckDelivery className="size-6" aria-hidden="true" />
                </span>
                <Statistic
                  label="現在の状況"
                  value={isAbsent ? "ご不在で持ち戻り" : "配達中"}
                  hint={
                    isAbsent
                      ? "再配達のご依頼をお願いします"
                      : "本日中にお届け予定です"
                  }
                />
              </div>

              <div className="grid grid-cols-2 gap-3 rounded-lg bg-muted/40 p-3">
                <Statistic label="お届け予定" value="本日 18〜20時" />
                <Statistic label="お届け先" value={RECIPIENT.name} />
              </div>
            </CardContent>
          </Card>
        </section>

        {/* ── ご不在アラート ── */}
        {isAbsent ? (
          <Alert variant="warning">
            <IconBox className="size-4" aria-hidden="true" />
            <AlertTitle>お荷物は持ち戻りになりました</AlertTitle>
            <AlertDescription>
              ご不在のため不在票を投函しました。下のフォームから再配達をご依頼ください。本日19時までのご依頼で本日中の再配達も承れます。
            </AlertDescription>
          </Alert>
        ) : null}

        {/* ── 配送状況の追跡（複数日にまたがる） ── */}
        <section aria-labelledby="tracking-heading">
          <h2
            id="tracking-heading"
            className="mb-2 text-sm font-semibold text-foreground"
          >
            お荷物の状況
          </h2>
          <Card>
            <CardContent className="p-4">
              <RouteStops
                stops={stops}
                aria-label="配送状況のタイムライン"
                statusLabels={{
                  completed: "済",
                  current: "現在",
                  failed: "ご不在",
                  pending: "未",
                }}
                timeLabels={{ actual: "" }}
              />
              <p className="mt-1 text-xs text-muted-foreground">
                ※ 表示は受付（6/27）から最新（6/29）までの記録です。
              </p>
            </CardContent>
          </Card>
        </section>

        {/* ── ご不在・再配達のご依頼 ── */}
        {isAbsent ? (
          <section aria-labelledby="redelivery-heading">
            <h2
              id="redelivery-heading"
              className="mb-2 text-sm font-semibold text-foreground"
            >
              再配達のご依頼
            </h2>
            <Card>
              <CardContent className="flex flex-col gap-5 p-4">
                {/* 受け取り日 */}
                <div className="flex flex-col gap-1.5">
                  <label
                    htmlFor="redelivery-date"
                    className="text-sm font-medium text-foreground"
                  >
                    受け取り日
                  </label>
                  <DatePicker
                    id="redelivery-date"
                    value={redeliveryDate}
                    onValueChange={setRedeliveryDate}
                    locale={ja}
                    dateFormat="M月d日(E)"
                    placeholder="日付を選択"
                    startMonth={new Date("2026-06-01")}
                    endMonth={new Date("2026-07-31")}
                  />
                </div>

                {/* 受け取り時間帯（時間BAND） */}
                <fieldset className="flex flex-col gap-1.5">
                  <legend className="text-sm font-medium text-foreground">
                    受け取り時間帯
                  </legend>
                  <SegmentedControl
                    options={TIME_BANDS}
                    value={timeBand}
                    onValueChange={setTimeBand}
                    aria-label="受け取り時間帯"
                    fullWidth
                    size="sm"
                  />
                  <p className="text-xs text-muted-foreground">
                    時間帯でのご指定です。時刻のご指定はできません。
                  </p>
                </fieldset>

                {/* 受け取り方法 */}
                <fieldset className="flex flex-col gap-2">
                  <legend className="mb-0.5 text-sm font-medium text-foreground">
                    受け取り方法
                  </legend>
                  <RadioCardGroup
                    value={receiveMethod}
                    onValueChange={setReceiveMethod}
                    aria-label="受け取り方法"
                  >
                    {RECEIVE_METHODS.map((m) => (
                      <RadioCard
                        key={m.value}
                        value={m.value}
                        title={m.label}
                        description={m.description}
                        highlight={m.note}
                      />
                    ))}
                  </RadioCardGroup>
                </fieldset>

                {/* 確認サマリ */}
                <div className="rounded-lg bg-muted/40 p-3 text-sm">
                  <p className="text-foreground">
                    <span className="text-muted-foreground">ご指定内容：</span>
                    {dateLabel} ／ {bandLabel} ／ {methodLabel}
                  </p>
                </div>
              </CardContent>
            </Card>
          </section>
        ) : null}

        {/* ── 通知設定 ── */}
        <section aria-labelledby="notify-heading">
          <h2
            id="notify-heading"
            className="mb-2 text-sm font-semibold text-foreground"
          >
            通知設定
          </h2>
          <Card>
            <CardContent className="flex flex-col gap-1 p-2">
              {NOTIFY_CHANNELS.map((ch, i) => (
                <React.Fragment key={ch.id}>
                  {i > 0 ? <Separator /> : null}
                  <Switch
                    className="px-2 py-2"
                    checked={notify[ch.id]}
                    onCheckedChange={(v) =>
                      setNotify((p) => ({ ...p, [ch.id]: v }))
                    }
                    label={ch.label}
                    description={ch.description}
                  />
                </React.Fragment>
              ))}
            </CardContent>
          </Card>
        </section>

        {/* ── お届け先 / ご依頼主 / 配達担当 ── */}
        <section aria-labelledby="parties-heading">
          <h2
            id="parties-heading"
            className="mb-2 text-sm font-semibold text-foreground"
          >
            お届け先・ご依頼主
          </h2>
          <Card>
            <CardContent className="flex flex-col gap-3 p-4 text-sm">
              <div className="flex items-start gap-2">
                <IconUser className="mt-0.5 size-4 shrink-0 text-muted-foreground" aria-hidden="true" />
                <div className="flex min-w-0 flex-col">
                  <span className="text-xs text-muted-foreground">お届け先</span>
                  <span className="text-foreground">{RECIPIENT.name}</span>
                  <span className="text-muted-foreground">{RECIPIENT.address}</span>
                </div>
              </div>
              <Separator />
              <div className="flex items-start gap-2">
                <IconBox className="mt-0.5 size-4 shrink-0 text-muted-foreground" aria-hidden="true" />
                <div className="flex min-w-0 flex-col">
                  <span className="text-xs text-muted-foreground">ご依頼主</span>
                  <span className="text-foreground">{SENDER.name}</span>
                </div>
              </div>
              <Separator />
              <div className="flex items-start gap-2">
                <IconTruckDelivery className="mt-0.5 size-4 shrink-0 text-muted-foreground" aria-hidden="true" />
                <div className="flex min-w-0 flex-col">
                  <span className="text-xs text-muted-foreground">配達担当</span>
                  <span className="text-foreground">{DRIVER.name}</span>
                </div>
              </div>
            </CardContent>
          </Card>
        </section>

        {/* ── 配送履歴 ── */}
        <section aria-labelledby="history-heading">
          <h2
            id="history-heading"
            className="mb-2 text-sm font-semibold text-foreground"
          >
            配送履歴
          </h2>
          <div className="flex flex-col gap-2">
            {PAST_PARCELS.map((p) => (
              <ListCard
                key={p.no}
                title={p.summary}
                description={`お問い合わせ番号 ${p.no}`}
                status={<Badge variant={PAST_TONE[p.tone]}>{p.status}</Badge>}
                meta={p.date}
                onSelect={() => {}}
              />
            ))}
          </div>
        </section>
      </main>

      {/* ── 常時表示の下部アクション ── */}
      <BottomActionBar
        sticky
        maxWidth="md"
        actions={
          <Button
            variant="primary"
            size="lg"
            className="w-full"
            disabled={isAbsent && !redeliveryDate}
          >
            {isAbsent ? "再配達を依頼する" : "追跡を更新する"}
          </Button>
        }
      >
        {isAbsent ? (
          <div className="flex min-w-0 flex-col">
            <span className="text-xs text-muted-foreground">ご希望</span>
            <span className="truncate text-sm font-medium text-foreground">
              {dateLabel.replace(/\(.\)$/, "")} {bandLabel}
            </span>
          </div>
        ) : (
          <div className="flex min-w-0 flex-col">
            <span className="text-xs text-muted-foreground">お届け予定</span>
            <span className="truncate text-sm font-medium text-foreground">
              本日 18〜20時
            </span>
          </div>
        )}
      </BottomActionBar>
    </div>
  );
}

// 宅配便 個人向け 配送追跡・再配達 — ドメインデータ（サーバー安全 / 関数propsなし）
// "use client" を付けない純粋モジュール。フォーマッタはサーバーでも呼べる素の関数。

export const CARRIER = {
  name: "群青運輸",
  service: "ぐんじょう宅急便",
  supportTel: "0120-19-0123",
} as const;

/** お問い合わせ番号（送り状番号 / 伝票番号 / 追跡番号）— 12桁 4-4-4 区切り表示。 */
export const TRACKING_NO = "4823-7710-9265";

export type ParcelStatus =
  | "accepted" // 受付
  | "shipped" // 発送
  | "in_transit" // 輸送中
  | "at_branch" // 配達店到着
  | "out_for_delivery" // 配達中
  | "delivered" // お届け完了
  | "absent"; // ご不在（持ち戻り）

/** RouteStops の status と対応させるためのマップ（pending/current/completed/failed）。 */
export interface TrackingStep {
  id: string;
  /** お荷物の状況 ラベル */
  label: string;
  /** RouteStops 用 status */
  state: "completed" | "current" | "failed" | "pending";
  /** 日付 (YYYY-MM-DD) — タイムライン上の日。複数日にまたがる。 */
  date?: string;
  /** 時刻 (HH:MM) */
  time?: string;
  /** 取扱店・営業所 */
  branch?: string;
  /** 補足（不在理由・サイン省略 など） */
  note?: string;
}

