/** 受け取り時間帯（時間BAND — 正確な時刻ではない）。 */
export interface TimeBand {
  value: string;
  label: string;
}
export const TIME_BANDS: TimeBand[] = [
  { value: "am", label: "午前中" },
  { value: "1416", label: "14〜16時" },
  { value: "1618", label: "16〜18時" },
  { value: "1820", label: "18〜20時" },
  { value: "1921", label: "19〜21時" },
];

/** 受け取り方法。 */
export interface ReceiveMethod {
  value: string;
  label: string;
  description: string;
  note?: string;
}
export const RECEIVE_METHODS: ReceiveMethod[] = [
  {
