/** 通知設定チャネル。 */
export interface NotifyChannel {
  id: "push" | "line" | "mail";
  label: string;
  description: string;
}
export const NOTIFY_CHANNELS: NotifyChannel[] = [
  { id: "push", label: "プッシュ通知", description: "アプリでお届け前にお知らせ" },
  { id: "line", label: "LINE通知", description: "LINEでお荷物の状況をお知らせ" },
  { id: "mail", label: "メール通知", description: "ご登録のメールアドレスへ" },
