  { no: "4790-5521-8810", summary: "クール便（冷蔵）", status: "お届け完了", date: "6/15", tone: "delivered" },
  { no: "4773-1180-2245", summary: "書類（ネコポス）", status: "お届け完了", date: "6/9", tone: "delivered" },
];

/** お届け先・ご依頼主。 */
export const RECIPIENT = {
  name: "鈴木 一郎 様",
  address: "東京都世田谷区宮坂2-X-XX ハイツ宮坂 305",
} as const;
export const SENDER = {
  name: "Aマート オンラインストア",
} as const;
export const DRIVER = {
  name: "高橋（世田谷宮坂営業所）",
} as const;

// ---- サーバー安全な純粋フォーマッタ（"use client" 不要・関数propsではない） ----

const WEEKDAY_JA = ["日", "月", "火", "水", "木", "金", "土"] as const;

/** "2026-06-29" → "6/29(月)" */
export function formatJaShortDate(iso: string): string {
  const [, m, d] = iso.split("-").map(Number);
  const wd = WEEKDAY_JA[new Date(iso + "T00:00:00").getDay()];
  return `${m}/${d}(${wd})`;
}

/** Date → "6月29日(月)" */
export function formatJaLongDate(date: Date): string {
  const m = date.getMonth() + 1;
  const d = date.getDate();
  const wd = WEEKDAY_JA[date.getDay()];
  return `${m}月${d}日(${wd})`;
}

/** ステップの日付ラベルが直前と変わったかを判定し、日付見出しを返す。 */
export function dayHeadingFor(steps: TrackingStep[], index: number): string | null {
  const cur = steps[index]?.date;
  if (!cur) return null;
  const prev = index > 0 ? steps[index - 1]?.date : undefined;
  return cur !== prev ? formatJaShortDate(cur) : null;
}
